import{c as a,Q as t,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"The Decoder — 2026-05-14","description":"","frontmatter":{"title":"The Decoder — 2026-05-14","date":"2026-05-14T00:00:00.000Z","source":"The Decoder","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-14-the-decoder.md","filePath":"research/ai-news/2026-05/2026-05-14-the-decoder.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-14-the-decoder.md"};function i(s,e,p,d,c,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🔓-the-decoder-—-2026-05-14" tabindex="-1">🔓 The Decoder — 2026-05-14 <a class="header-anchor" href="#🔓-the-decoder-—-2026-05-14" aria-label="Permalink to &quot;🔓 The Decoder — 2026-05-14&quot;">​</a></h1><blockquote><p>企業 AI 開發與模型應用日報，涵蓋 AI 社會影響（英語媒體） 來源：<a href="https://the-decoder.com/feed/" target="_blank" rel="noreferrer">The Decoder</a></p></blockquote><hr><h2 id="tencent-plans-to-ramp-up-ai-spending-as-china-s-chip-supply-allegedly-improves" tabindex="-1"><a href="https://the-decoder.com/tencent-plans-to-ramp-up-ai-spending-as-chinas-chip-supply-allegedly-improves/" target="_blank" rel="noreferrer">Tencent plans to ramp up AI spending as China&#39;s chip supply allegedly improves</a> <a class="header-anchor" href="#tencent-plans-to-ramp-up-ai-spending-as-china-s-chip-supply-allegedly-improves" aria-label="Permalink to &quot;[Tencent plans to ramp up AI spending as China&#39;s chip supply allegedly improves](https://the-decoder.com/tencent-plans-to-ramp-up-ai-spending-as-chinas-chip-supply-allegedly-improves/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-13</em></p><p>Tencent plans to significantly boost AI infrastructure spending in the second half of 2026, as Chinese chipmakers ramp up domestic AI chip production. The company also posted strong first-quarter results and is in talks for a stake in Deepseek.</p><p>The article <a href="https://the-decoder.com/tencent-plans-to-ramp-up-ai-spending-as-chinas-chip-supply-allegedly-improves/" target="_blank" rel="noreferrer">Tencent plans to ramp up AI spending as China&#39;s chip supply allegedly improves</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-overtakes-openai-in-b2b-adoption-for-the-first-time-according-to-ramp-spending-data" tabindex="-1"><a href="https://the-decoder.com/anthropic-overtakes-openai-in-b2b-adoption-for-the-first-time-according-to-ramp-spending-data/" target="_blank" rel="noreferrer">Anthropic overtakes OpenAI in B2B adoption for the first time according to Ramp spending data</a> <a class="header-anchor" href="#anthropic-overtakes-openai-in-b2b-adoption-for-the-first-time-according-to-ramp-spending-data" aria-label="Permalink to &quot;[Anthropic overtakes OpenAI in B2B adoption for the first time according to Ramp spending data](https://the-decoder.com/anthropic-overtakes-openai-in-b2b-adoption-for-the-first-time-according-to-ramp-spending-data/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-13</em></p><p>Anthropic now leads OpenAI in B2B adoption for the first time, with 34.4 percent of US companies on the Ramp AI Index compared to OpenAI&#39;s 32.3 percent. Anthropic quadrupled its reach in just one year, but three factors could erode that lead quickly.</p><p>The article <a href="https://the-decoder.com/anthropic-overtakes-openai-in-b2b-adoption-for-the-first-time-according-to-ramp-spending-data/" target="_blank" rel="noreferrer">Anthropic overtakes OpenAI in B2B adoption for the first time according to Ramp spending data</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="meta-ai-gets-a-private-mode-where-no-conversation-data-is-stored-on-servers" tabindex="-1"><a href="https://the-decoder.com/meta-ai-gets-a-private-mode-where-no-conversation-data-is-stored-on-servers/" target="_blank" rel="noreferrer">Meta AI gets a private mode where no conversation data is stored on servers</a> <a class="header-anchor" href="#meta-ai-gets-a-private-mode-where-no-conversation-data-is-stored-on-servers" aria-label="Permalink to &quot;[Meta AI gets a private mode where no conversation data is stored on servers](https://the-decoder.com/meta-ai-gets-a-private-mode-where-no-conversation-data-is-stored-on-servers/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-13</em></p><p>Meta is rolling out &quot;Incognito Chat&quot; for Meta AI on WhatsApp and in the Meta AI app. According to Mark Zuckerberg, conversations are processed in a protected server environment that even Meta can&#39;t access, and chat histories disappear when the session ends. Zuckerberg claims Meta is the first AI lab to offer this level of private AI usage.</p><p>The article <a href="https://the-decoder.com/meta-ai-gets-a-private-mode-where-no-conversation-data-is-stored-on-servers/" target="_blank" rel="noreferrer">Meta AI gets a private mode where no conversation data is stored on servers</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="anthropic-launches-claude-for-small-business-to-embed-ai-into-the-tools-you-forgot-you-pay-for" tabindex="-1"><a href="https://the-decoder.com/anthropic-launches-claude-for-small-business-to-embed-ai-into-the-tools-you-forgot-you-pay-for/" target="_blank" rel="noreferrer">Anthropic launches Claude for Small Business to embed AI into the tools you forgot you pay for</a> <a class="header-anchor" href="#anthropic-launches-claude-for-small-business-to-embed-ai-into-the-tools-you-forgot-you-pay-for" aria-label="Permalink to &quot;[Anthropic launches Claude for Small Business to embed AI into the tools you forgot you pay for](https://the-decoder.com/anthropic-launches-claude-for-small-business-to-embed-ai-into-the-tools-you-forgot-you-pay-for/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-13</em></p><p>Anthropic is launching &quot;Claude for Small Business,&quot; a package of 15 agent-based workflows and integrations for tools like QuickBooks, PayPal, and HubSpot. The company is also rolling out free training courses and a workshop tour across ten US cities as it pushes to bring AI directly to small businesses.</p><p>The article <a href="https://the-decoder.com/anthropic-launches-claude-for-small-business-to-embed-ai-into-the-tools-you-forgot-you-pay-for/" target="_blank" rel="noreferrer">Anthropic launches Claude for Small Business to embed AI into the tools you forgot you pay for</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr><h2 id="luma-opens-uni-1-1-image-model-api-at-prices-and-quality-matching-openai-and-google" tabindex="-1"><a href="https://the-decoder.com/luma-opens-uni-1-1-image-model-api-at-prices-and-quality-matching-openai-and-google/" target="_blank" rel="noreferrer">Luma opens Uni-1.1 image model API at prices and quality matching OpenAI and Google</a> <a class="header-anchor" href="#luma-opens-uni-1-1-image-model-api-at-prices-and-quality-matching-openai-and-google" aria-label="Permalink to &quot;[Luma opens Uni-1.1 image model API at prices and quality matching OpenAI and Google](https://the-decoder.com/luma-opens-uni-1-1-image-model-api-at-prices-and-quality-matching-openai-and-google/)&quot;">​</a></h2><p><em>🔓 The Decoder | 2026-05-13</em></p><p>Luma is making its Uni-1.1 image model available via API, with prices starting at $0.04 per image at 2,048-pixel resolution. On the Arena leaderboard, the model ranks third, right behind Google and OpenAI. The API includes web search, built-in reasoning, and support for up to nine reference images.</p><p>The article <a href="https://the-decoder.com/luma-opens-uni-1-1-image-model-api-at-prices-and-quality-matching-openai-and-google/" target="_blank" rel="noreferrer">Luma opens Uni-1.1 image model API at prices and quality matching OpenAI and Google</a> appeared first on <a href="https://the-decoder.com" target="_blank" rel="noreferrer">The Decoder</a>.</p><hr>',28)])])}const u=a(n,[["render",i]]);export{m as __pageData,u as default};
